// // This module computes the logical AND of all possible 2-input OR combinations of three inputs (A, B, and C). The output Y will be LOW if at least two of the three inputs are LOW, effectively functioning as an anti-majority gate for three inputs.
module top_module(
    A,
    B,
    C,
    Y
);input A, B, C;
    output Y;

    wire and1, and2, and3;
    wire or1, or2;

    assign and1 = A & B;
    assign and2 = A & C;
    assign and3 = B & C;
    assign or1 = and1 | and2;
    assign or2 = or1 | and3;
    assign Y = or2;

endmodule
